/**
 * flow-changelog-detector.js — Detect what changed in a Salesforce flow since its last documentation.
 *
 * Compares flow XML metadata against existing documentation to classify changes
 * (new, logic, variables, description, unchanged) and generate change descriptions.
 * Uses git history to determine last-modified dates.
 *
 * Usage:
 *   node scripts/flow-changelog-detector.js MyFlowApiName
 *   node scripts/flow-changelog-detector.js --all                   # All flows with docs
 *   node scripts/flow-changelog-detector.js --category account      # All in category
 *   node scripts/flow-changelog-detector.js --changed               # Only flows changed since last doc
 *   node scripts/flow-changelog-detector.js --table                 # Markdown table output
 *   node scripts/flow-changelog-detector.js --all --table           # Combine flags
 *
 * Options:
 *   --metadata-path <path>      Path to SFDX metadata directory (default: force-app/main/default)
 *   --docs-path <path>          Path to flow docs directory (default: docs/flows)
 *   --categories-path <path>    Path to flow categories file (default: <docs-path>/flow-categories.json)
 *                                JSON: { "category_name": ["FlowName1", ...] }
 *                                JS module: exports a categorize(flowName) function
 *   --filters-path <path>       Path to flow-filters.json for skip lists (default: none)
 *   --all                       Analyze all documented flows
 *   --changed                   Only show flows changed since last documentation
 *   --category <name>           Filter to a single category
 *   --table                     Output as markdown table (default: JSON)
 *   --help                      Show this help message
 *
 * Exit codes:
 *   0 — Success
 *   1 — Error (missing paths, bad args)
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

const repoRoot = path.resolve(__dirname, "..");

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

const cliArgs = process.argv.slice(2);

if (cliArgs.includes("--help")) {
  const lines = [];
  lines.push("flow-changelog-detector.js — Detect what changed in Salesforce flows since last documentation");
  lines.push("");
  lines.push("Usage:");
  lines.push("  node scripts/flow-changelog-detector.js <FlowName> [FlowName...]");
  lines.push("  node scripts/flow-changelog-detector.js --all [--table] [--changed]");
  lines.push("  node scripts/flow-changelog-detector.js --category <name> [--table] [--changed]");
  lines.push("");
  lines.push("Options:");
  lines.push("  --metadata-path <path>      Path to SFDX metadata directory (default: force-app/main/default)");
  lines.push("  --docs-path <path>          Path to flow docs directory (default: docs/flows)");
  lines.push("  --categories-path <path>    Path to flow categories file (JSON map or JS module)");
  lines.push("  --filters-path <path>       Path to flow-filters.json for skip lists (default: none)");
  lines.push("  --all                       Analyze all documented flows");
  lines.push("  --changed                   Only show flows changed since last documentation");
  lines.push("  --category <name>           Filter to a single category");
  lines.push("  --table                     Output as markdown table (default: JSON)");
  lines.push("  --help                      Show this help message");
  lines.push("");
  lines.push("Categories file formats:");
  lines.push("  JSON: { \"category_name\": [\"FlowName1\", \"FlowName2\"] }");
  lines.push("  JS module: module.exports = { categorize(flowName) { return 'category'; } }");
  console.log(lines.join("\n"));
  process.exit(0);
}

function getArgValue(argList, name) {
  const idx = argList.indexOf(name);
  if (idx === -1 || idx + 1 >= argList.length) return null;
  return argList[idx + 1];
}

// Resolve paths from CLI args
const metadataRel = getArgValue(cliArgs, "--metadata-path") || "force-app/main/default";
const docsRel = getArgValue(cliArgs, "--docs-path") || "docs/flows";
const flowDir = path.resolve(repoRoot, metadataRel, "flows");
const docsDir = path.resolve(repoRoot, docsRel);

// ---------------------------------------------------------------------------
// Load categories (optional — falls back to "other" for all flows)
// ---------------------------------------------------------------------------

const categoriesPathArg = getArgValue(cliArgs, "--categories-path");
const categoriesPath = categoriesPathArg
  ? path.resolve(repoRoot, categoriesPathArg)
  : path.join(docsDir, "flow-categories.json");

let categorizeFn;

if (fs.existsSync(categoriesPath)) {
  if (categoriesPath.endsWith(".js")) {
    const mod = require(categoriesPath);
    categorizeFn = mod.categorize || mod.cat || mod;
  } else {
    const catMap = JSON.parse(fs.readFileSync(categoriesPath, "utf8"));
    const flowToCategory = {};
    for (const [cat, flows] of Object.entries(catMap)) {
      if (cat === "_labels") continue;
      for (const fn of flows) {
        flowToCategory[fn] = cat;
      }
    }
    categorizeFn = (name) => flowToCategory[name] || "other";
  }
} else {
  categorizeFn = () => "other";
}

// ---------------------------------------------------------------------------
// Load filters (optional)
// ---------------------------------------------------------------------------

const filtersPathArg = getArgValue(cliArgs, "--filters-path");
const filtersPath = filtersPathArg ? path.resolve(repoRoot, filtersPathArg) : null;

const skipSets = { temp: new Set(), onetime: new Set(), sunset: new Set(), platform: new Set() };

if (filtersPath && fs.existsSync(filtersPath)) {
  const filters = JSON.parse(fs.readFileSync(filtersPath, "utf8"));
  if (filters.skip_temp) skipSets.temp = new Set(filters.skip_temp.explicit || []);
  if (filters.skip_onetime) skipSets.onetime = new Set(filters.skip_onetime.explicit || []);
  if (filters.skip_sunset) skipSets.sunset = new Set(filters.skip_sunset.explicit || []);
  if (filters.skip_platform) skipSets.platform = new Set(filters.skip_platform.explicit || []);
}

function catFn(name) {
  if (skipSets.temp.has(name)) return "SKIP_temp";
  if (skipSets.onetime.has(name)) return "SKIP_onetime";
  if (skipSets.sunset.has(name)) return "SKIP_sunset";
  if (skipSets.platform.has(name)) return "SKIP_platform";
  return categorizeFn(name);
}

// ---------------------------------------------------------------------------
// Parse remaining CLI args
// ---------------------------------------------------------------------------

const opts = {
  all: cliArgs.includes("--all"),
  changed: cliArgs.includes("--changed"),
  table: cliArgs.includes("--table"),
  category: getArgValue(cliArgs, "--category"),
};

// Positional flow names (anything not a flag or flag value)
const flagsWithValues = new Set([
  "--metadata-path",
  "--docs-path",
  "--categories-path",
  "--filters-path",
  "--category",
]);
const flagsNoValue = new Set(["--all", "--changed", "--table", "--help"]);

const positionalNames = [];
for (let i = 0; i < cliArgs.length; i++) {
  const arg = cliArgs[i];
  if (flagsWithValues.has(arg)) {
    i++; // skip the value
    continue;
  }
  if (flagsNoValue.has(arg)) continue;
  positionalNames.push(arg);
}

// --- Main ---
const flowNames = resolveFlowNames(opts, positionalNames);
const results = flowNames.map((name) => analyzeFlow(name)).filter(Boolean);

if (opts.changed) {
  const changedResults = results.filter(
    (r) => r.classification !== "unchanged"
  );
  output(changedResults, opts);
} else {
  output(results, opts);
}

// ============================================================
// Functions
// ============================================================

function resolveFlowNames(opts, positionalNames) {
  if (positionalNames.length > 0) {
    return positionalNames;
  }

  if (opts.all || opts.changed) {
    return findDocumentedFlows(opts.category);
  }

  if (opts.category) {
    return findFlowsInCategory(opts.category);
  }

  console.error(
    "Usage: node scripts/flow-changelog-detector.js <FlowName> [FlowName...]"
  );
  console.error(
    "       node scripts/flow-changelog-detector.js --all [--table] [--changed]"
  );
  console.error(
    "       node scripts/flow-changelog-detector.js --category <name> [--table] [--changed]"
  );
  console.error("");
  console.error("Run with --help for full usage details.");
  process.exit(1);
}

function findDocumentedFlows(categoryFilter) {
  const names = [];
  if (!fs.existsSync(docsDir)) return names;

  const categories = fs.readdirSync(docsDir).filter((d) => {
    const full = path.join(docsDir, d);
    return fs.statSync(full).isDirectory() && d !== "vendor";
  });

  for (const cat of categories) {
    if (categoryFilter && cat !== categoryFilter) continue;
    const catDir = path.join(docsDir, cat);
    const files = fs
      .readdirSync(catDir)
      .filter((f) => f.endsWith(".md") && f !== "_index.md");
    for (const f of files) {
      names.push(f.replace(".md", ""));
    }
  }

  return names.sort();
}

function findFlowsInCategory(category) {
  if (!fs.existsSync(flowDir)) return [];

  const files = fs
    .readdirSync(flowDir)
    .filter((f) => f.endsWith(".flow-meta.xml"));
  const names = [];
  for (const f of files) {
    const name = f.replace(".flow-meta.xml", "");
    if (catFn(name) === category) {
      names.push(name);
    }
  }
  return names.sort();
}

function analyzeFlow(name) {
  const xmlPath = path.join(flowDir, name + ".flow-meta.xml");
  if (!fs.existsSync(xmlPath)) {
    return {
      name,
      category: catFn(name),
      classification: "missing_xml",
      change_description: "Flow XML not found in repo.",
      xml_last_modified: null,
      doc_last_documented: null,
      days_stale: null,
      element_counts: null,
    };
  }

  const xml = fs.readFileSync(xmlPath, "utf8");
  const category = catFn(name);
  const extracted = extractFlowElements(xml);
  const elementCounts = countElements(extracted);

  const docPath = findDocPath(name, category);
  const docInfo = docPath ? parseDocFile(docPath) : null;

  const xmlLastModified = getGitLastModified(xmlPath);

  const classification = classifyChange(extracted, docInfo, xmlLastModified);
  const changeDescription = generateChangeDescription(
    classification,
    extracted,
    elementCounts
  );

  let daysStale = null;
  if (docInfo && docInfo.lastDocumented && xmlLastModified) {
    const docDate = new Date(docInfo.lastDocumented);
    const xmlDate = new Date(xmlLastModified);
    if (xmlDate > docDate) {
      daysStale = Math.floor((xmlDate - docDate) / (1000 * 60 * 60 * 24));
    } else {
      daysStale = 0;
    }
  }

  return {
    name,
    category,
    classification,
    change_description: changeDescription,
    xml_last_modified: xmlLastModified,
    doc_last_documented: docInfo ? docInfo.lastDocumented : null,
    days_stale: daysStale,
    element_counts: elementCounts,
  };
}

function extractFlowElements(xml) {
  return {
    description: extractTopDescription(xml),
    start: extractStartBlock(xml),
    decisions: extractNamedElements(xml, "decisions"),
    recordCreates: extractNamedElements(xml, "recordCreates"),
    recordUpdates: extractNamedElements(xml, "recordUpdates"),
    recordDeletes: extractNamedElements(xml, "recordDeletes"),
    recordLookups: extractNamedElements(xml, "recordLookups"),
    actionCalls: extractNamedElements(xml, "actionCalls"),
    subflows: extractNamedElements(xml, "subflows"),
    assignments: extractNamedElements(xml, "assignments"),
    variables: extractVariables(xml),
  };
}

function extractTopDescription(xml) {
  const m = xml.match(/<description>([\s\S]*?)<\/description>/);
  return m ? m[1].trim() : null;
}

function extractStartBlock(xml) {
  const m = xml.match(/<start>([\s\S]*?)<\/start>/);
  if (!m) return null;
  const block = m[1];

  const triggerType = tagVal(block, "triggerType");
  const object = tagVal(block, "object");
  const recordTriggerType = tagVal(block, "recordTriggerType");

  const filterMatches = block.match(/<filters>[\s\S]*?<\/filters>/g) || [];
  const scheduledPaths =
    block.match(/<scheduledPaths>[\s\S]*?<\/scheduledPaths>/g) || [];

  return {
    triggerType,
    object,
    recordTriggerType,
    filterCount: filterMatches.length,
    scheduledPathCount: scheduledPaths.length,
    raw: block,
  };
}

function extractNamedElements(xml, tag) {
  const re = new RegExp("<" + tag + ">([\\s\\S]*?)</" + tag + ">", "g");
  const elements = [];
  let match;
  while ((match = re.exec(xml)) !== null) {
    const block = match[1];
    const name = tagVal(block, "name");
    const label = tagVal(block, "label");
    elements.push({ name: name || "(unnamed)", label: label || "" });
  }
  return elements;
}

function extractVariables(xml) {
  const re = /<variables>([\s\S]*?)<\/variables>/g;
  const vars = [];
  let match;
  while ((match = re.exec(xml)) !== null) {
    const block = match[1];
    vars.push({
      name: tagVal(block, "name") || "(unnamed)",
      dataType: tagVal(block, "dataType") || "Unknown",
      isInput: tagVal(block, "isInput") === "true",
      isOutput: tagVal(block, "isOutput") === "true",
    });
  }
  return vars;
}

function countElements(extracted) {
  return {
    decisions: extracted.decisions.length,
    recordCreates: extracted.recordCreates.length,
    recordUpdates: extracted.recordUpdates.length,
    recordDeletes: extracted.recordDeletes.length,
    recordLookups: extracted.recordLookups.length,
    actionCalls: extracted.actionCalls.length + extracted.subflows.length,
    assignments: extracted.assignments.length,
    variables: extracted.variables.length,
  };
}

function findDocPath(name, category) {
  const primary = path.join(docsDir, category, name + ".md");
  if (fs.existsSync(primary)) return primary;

  if (!fs.existsSync(docsDir)) return null;

  const categories = fs.readdirSync(docsDir).filter((d) => {
    const full = path.join(docsDir, d);
    return fs.statSync(full).isDirectory();
  });

  for (const cat of categories) {
    const candidate = path.join(docsDir, cat, name + ".md");
    if (fs.existsSync(candidate)) return candidate;
  }

  return null;
}

function parseDocFile(docPath) {
  const content = fs.readFileSync(docPath, "utf8");

  const dateMatch = content.match(
    /\*\*Last Documented:\*\*\s*(\d{4}-\d{2}-\d{2})/
  );
  const lastDocumented = dateMatch ? dateMatch[1] : null;

  const decisionNames = [];
  const decisionRe = /decision[:\s]+[`"]?(\w+)[`"]?/gi;
  let m;
  while ((m = decisionRe.exec(content)) !== null) {
    decisionNames.push(m[1]);
  }

  const dmlNames = [];
  const dmlRe =
    /(?:record\s*(?:create|update|delete|lookup)|DML)[:\s]+[`"]?(\w+)[`"]?/gi;
  while ((m = dmlRe.exec(content)) !== null) {
    dmlNames.push(m[1]);
  }

  return {
    lastDocumented,
    decisionNames,
    dmlNames,
    hasContent: content.length > 0,
  };
}

function getGitLastModified(filePath) {
  try {
    const relPath = path.relative(repoRoot, filePath).replace(/\\/g, "/");
    const result = execSync('git log -1 --format=%ai -- "' + relPath + '"', {
      cwd: repoRoot,
      encoding: "utf8",
      stdio: ["pipe", "pipe", "pipe"],
    }).trim();
    if (!result) return null;
    return result.split(" ")[0];
  } catch (e) {
    return null;
  }
}

function classifyChange(extracted, docInfo, xmlLastModified) {
  if (!docInfo) return "new";
  if (!xmlLastModified) return "unknown";
  if (!docInfo.lastDocumented) return "new";

  const xmlDate = new Date(xmlLastModified);
  const docDate = new Date(docInfo.lastDocumented);

  if (xmlDate <= docDate) return "unchanged";

  const currentDecisionNames = extracted.decisions.map((d) => d.name);
  const currentDmlCount =
    extracted.recordCreates.length +
    extracted.recordUpdates.length +
    extracted.recordDeletes.length;
  const currentActionCount =
    extracted.actionCalls.length + extracted.subflows.length;

  const inputOutputVars = extracted.variables.filter(
    (v) => v.isInput || v.isOutput
  );
  if (
    inputOutputVars.length > 0 &&
    docInfo.decisionNames.length === 0 &&
    docInfo.dmlNames.length === 0
  ) {
    return "variables";
  }

  const docMentionsDecisions = docInfo.decisionNames.length > 0;
  const hasNewDecisions = currentDecisionNames.some(
    (n) => !docInfo.decisionNames.includes(n)
  );

  if (
    currentDecisionNames.length > 0 ||
    currentDmlCount > 0 ||
    currentActionCount > 0
  ) {
    if (hasNewDecisions || !docMentionsDecisions) {
      return "logic";
    }
  }

  if (
    currentDecisionNames.length === 0 &&
    currentDmlCount === 0 &&
    currentActionCount === 0
  ) {
    return "description";
  }

  return "logic";
}

function generateChangeDescription(classification, extracted, counts) {
  const triggerType = extracted.start
    ? extracted.start.triggerType || "Unknown"
    : "Unknown";
  const object = extracted.start
    ? extracted.start.object || "Unknown"
    : "Unknown";
  const dmlCount =
    counts.recordCreates + counts.recordUpdates + counts.recordDeletes;

  switch (classification) {
    case "new": {
      const desc =
        "New " +
        triggerType +
        " flow on " +
        object +
        ". " +
        counts.decisions +
        " decisions, " +
        dmlCount +
        " DML operations.";
      return truncate(desc, 120);
    }
    case "logic": {
      const decisionNames = extracted.decisions.map((d) => d.name);
      if (decisionNames.length > 0) {
        const nameStr =
          decisionNames.slice(0, 3).join(", ") +
          (decisionNames.length > 3
            ? " (+" + (decisionNames.length - 3) + " more)"
            : "");
        const desc =
          "Updated decision logic: " +
          nameStr +
          ". " +
          dmlCount +
          " DML operations.";
        return truncate(desc, 120);
      }
      return truncate(
        "Updated flow logic. " +
          dmlCount +
          " DML operations, " +
          counts.actionCalls +
          " action calls.",
        120
      );
    }
    case "trigger": {
      return truncate("Modified trigger conditions on " + object + ".", 120);
    }
    case "variables": {
      const inputVars = extracted.variables.filter((v) => v.isInput).length;
      const outputVars = extracted.variables.filter((v) => v.isOutput).length;
      return truncate(
        "Variable changes: " +
          inputVars +
          " input, " +
          outputVars +
          " output of " +
          counts.variables +
          " total.",
        120
      );
    }
    case "description": {
      return "Description updated only.";
    }
    case "unchanged": {
      return "No changes since last documentation.";
    }
    case "missing_xml": {
      return "Flow XML not found in repo.";
    }
    case "unknown": {
      return "Unable to determine change type (no git history).";
    }
    default:
      return "Unclassified change.";
  }
}

function truncate(str, maxLen) {
  if (str.length <= maxLen) return str;
  return str.substring(0, maxLen - 3) + "...";
}

function output(results, opts) {
  if (results.length === 0) {
    if (opts.table) {
      console.log("No flows matched the given criteria.");
    } else {
      process.stdout.write("[]\n");
    }
    return;
  }

  if (opts.table) {
    printTable(results);
  } else {
    process.stdout.write(JSON.stringify(results, null, 2) + "\n");
  }
}

function printTable(results) {
  const header =
    "| Flow | Category | Classification | Days Stale | Change Description |";
  const sep =
    "|------|----------|---------------|------------|-------------------|";
  const lines = [header, sep];

  for (const r of results) {
    const name = r.name.length > 40 ? r.name.substring(0, 37) + "..." : r.name;
    const stale = r.days_stale !== null ? String(r.days_stale) : "-";
    const desc =
      r.change_description.length > 60
        ? r.change_description.substring(0, 57) + "..."
        : r.change_description;
    lines.push(
      "| " +
        [name, r.category, r.classification, stale, desc].join(" | ") +
        " |"
    );
  }

  process.stdout.write(lines.join("\n") + "\n");
}

// ============================================================
// Utility helpers
// ============================================================

function tagVal(block, tag) {
  const re = new RegExp("<" + tag + ">([^<]*)</" + tag + ">");
  const m = block.match(re);
  return m ? m[1].trim() : null;
}
